_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec3 h = GP(vUv+hor) - GP(vUv-hor);
vec3 v = GP(vUv+ver) - GP(vUv-ver);
dz = vec2(h.r,v.r);
db = vec2(h.b,v.b);

uv1 = (vUv-0.5);
float l = length(uv1*q1);
ring = ceil(l);
uv1 += (noi(vUv/2,0)-1)*prog*0.2;
mskull=skull(uv1);
ret.b = 0.7+(noi(uv1/5,0).r*.5-0.3-0.09*l);
ret.b = sat(max(ret.b,mskull.y*0.9)) ;

vec2 noise = texture(sampler_noise_lq,vUv*4+rand_frame)-0.5;
uv2= vUv*0+0.1*noi(vUv/4,0);
ret.r = abs(noi(uv2/2+noise*uTexSize.zw*4*lf,0)-1)*(2-vRadius) ;
ret.r *= sat(texture(sampler_noise_hq,vUv/2+uTime*0.0034))*2*(1.3-vRadius);

ret.r = mix(ret.r, GetPixel(vUv-dz*uTexSize.zw*4).r,0.95);

float dit = sat(0.004/length(rp.y*.5+0.3-vUv.y-0.14*noi(vUv/8,0)))*0.25*(ring>4);
ret.r += dit;
ret.b-=dit*0.25;

ret.r += rp.x*(sat (3.3*noi(0.5*vAngle+uv2+db*rp.z,0)-4))*sat(1-1.6*ret.b)*(ret.b+0.1);

ret.r *= sat(1-GetBlur1(vUv).b*0.5) * sat(vRadius*1.5);
ret.r += exp(-8*l/q17*(1-prog));
ret.r+=mskull.x*2*sat(audioMidSmooth-0.5);

vec2 nn=texture(sampler_noise_lq,vUv*8+rand_frame)-0.5;
ret.g = max(ret.g,GetPixel(vUv+nn*0.01).g*0.4);

ret.r += (0.01/abs(noi(vUv*.2,rand_frame/8+uTime/8)-0.5))*mskull.y*sin(q16/2-vAngle)*audioMidSmooth*sat(q17-3.5);
ret.b-=.03*ret.r;
ret.rb *= sat (2-vRadius*1.3);
ret-=0.004;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

screen3 = vec3 ((vUv-0.5)*uAspect.xy,myzoom);
rsl0 = project (lav_gnd); vec3 struc;
  for (int m=1; m <= quality; m++) {
    rsl = fract(project (lav_gnd));
    r= sat(length(rsl-0.5));
    struc = get(rsl,r*1.5);
    lprof = sat (1-mix(struc.b, 0.75, sat(5.5-r*q1)))+0*(struc.r-0.5)/4;
    lav_gnd -= clamp01(4*(lprof-m/quality))*depth * (1-r);  }
rsl = project(lav_gnd);
dz.x = dot(GP(rsl+hor)-GP(rsl-hor),vec3(-0.2,0,1));
dz.y = dot(GP(rsl+ver)-GP(rsl-ver),vec3(-0.2,0,1));

l = length(rsl-0.5)*q1;
ring = ceil(l);
dz *= ring>4;
h1=fract(l);
float rill = (ring<6) * sat (-10+24*abs(fract(l)-0.5));
dz += rill*.15;

// spectrum calc
uv2=rsl-0.5;
float ang1 = atan3(uv2.x,uv2.y)*1.5;
float n=int(k1*ang1/M_PI);
float amp = GB1(vec2(0.015,n/k1)).g*(n>0)*(n<k1);

//licht
tmp=q5*(5-ring);
uv4 = rsl.xy+dz+ dot((rsl-0.5),vec2(sin(tmp+q6),cos(tmp)))-0.5;
licol = (0.2+roam_sin)/2;
li = 0.75*exp(-32*abs(uv4.x))*(GP(rsl).r<0.1)*licol;;

ret = GP(rsl).b*q7*sat(1-2*length(rsl-0.5-dz*8-vec2(q2,q3))) * texture(sampler_lichen,rsl*4);
ret-=rill*.25;

ret -= 8*sat(-dz.x);
ret = sat (ret);
ret += li*(ring<6)*(ring>1)*sat(5-l);
ret += lavcol(GP(rsl).r);

// spectrum draw
float dmask = sat(sin(2*ang1*k1)+0.5);
ret *= !(dmask * (l<3.8)*(l>3.2)*(n>0)*(n<k1));
ret += dmask * (l<3.8)*(l>(4-amp*0.8)) *vec3(0.3,0.6,2);
ret = sat(ret);

//Particles
uv2=(vUv-0.5)*vec2(0.92,1)+0.5; //linker Rand;
pa = GetPixel(uv2).g;
ret*=sat(1-(pa>0.3));
pa = max(pa, min(0.5,2*GetBlur2(uv2).g));
ret += lavcol(pa*1.5) ;

//####Funken
uv1 = (screen3.xy+0.5-vec2(q9,q10));
ret += 1/length(uv1)*q11*licol;
uv1 = (screen3.xy+0.5+8*GP(rsl).b*dz-vec2(q13,q14));
ret += 1/length(uv1)*q15*licol;

uv4=rsl0-0.5; //backrotation zu aufwendig
uv2=uv4; uv4.x+=uv2.y; uv4.y-=uv2.x;
float r = sat(-0.2-0.75*rp.x-(uv4.x)/2+lprof/2);
ret = mix(ret,  vec3 (.3+r,0.5,1),r);
ret = 1-exp(-ret*1.6);



  fragColor = ret;
}
